#include <string.h>
#include <stdlib.h>

static void *checked_calloc(size_t count, size_t size) {
    if (count == 0 || size == 0) {
        return NULL;
    }

    if (count > SIZE_MAX / size) {
        return NULL;
    }

    return calloc(count, size);
}

static bool run_state_alloc(float **buffer, size_t count) {
    if (buffer == NULL) {
        return false;
    }

    *buffer = checked_calloc(count, sizeof(float));
    return *buffer != NULL;
}

