use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub dim: usize,
    pub hidden_dim: usize,
    pub n_layers: usize,
    pub n_heads: usize,
    pub n_kv_heads: usize,
    pub vocab_size: usize,
    pub seq_len: usize,
}

impl Config {
    pub const HEADER_FIELDS: usize = 7;
    pub const HEADER_BYTES: usize = Self::HEADER_FIELDS * std::mem::size_of::<i32>();

    pub fn from_file(path: impl AsRef<Path>) -> io::Result<Self> {
        let mut file = File::open(path)?;
        Self::from_reader(&mut file)
    }

    pub fn from_reader(reader: &mut impl Read) -> io::Result<Self> {
        let dim = read_i32(reader)?;
        let hidden_dim = read_i32(reader)?;
        let n_layers = read_i32(reader)?;
        let n_heads = read_i32(reader)?;
        let n_kv_heads = read_i32(reader)?;
        let vocab_size = read_i32(reader)?;
        let seq_len = read_i32(reader)?;

        let config = Self {
            dim: to_usize("dim", dim)?,
            hidden_dim: to_usize("hidden_dim", hidden_dim)?,
            n_layers: to_usize("n_layers", n_layers)?,
            n_heads: to_usize("n_heads", n_heads)?,
            n_kv_heads: to_usize("n_kv_heads", n_kv_heads)?,
            vocab_size: to_usize("vocab_size", vocab_size)?,
            seq_len: to_usize("seq_len", seq_len)?,
        };

        config.validate()?;
        Ok(config)
    }

    pub fn validate(&self) -> io::Result<()> {
        if self.n_heads == 0 {
            return Err(invalid_data("n_heads must be greater than 0"));
        }
        if self.n_kv_heads == 0 {
            return Err(invalid_data("n_kv_heads must be greater than 0"));
        }
        if self.dim == 0 {
            return Err(invalid_data("dim must be greater than 0"));
        }
        if self.dim % self.n_heads != 0 {
            return Err(invalid_data("dim must be divisible by n_heads"));
        }
        if self.n_heads % self.n_kv_heads != 0 {
            return Err(invalid_data("n_heads must be divisible by n_kv_heads"));
        }
        Ok(())
    }

    pub fn head_size(&self) -> usize {
        self.dim / self.n_heads
    }

    pub fn kv_dim(&self) -> usize {
        self.dim * self.n_kv_heads / self.n_heads
    }
}

fn read_i32(reader: &mut impl Read) -> io::Result<i32> {
    let mut bytes = [0_u8; 4];
    reader.read_exact(&mut bytes)?;
    Ok(i32::from_le_bytes(bytes))
}

fn to_usize(field: &str, value: i32) -> io::Result<usize> {
    usize::try_from(value).map_err(|_| invalid_data(&format!("{field} must be non-negative")))
}

fn invalid_data(message: &str) -> io::Error {
    io::Error::new(io::ErrorKind::InvalidData, message)
}

#[cfg(test)]
mod tests {
    use super::Config;
    use std::io::Cursor;

    #[test]
    fn reads_config_from_binary_header() {
        let values = [4096_i32, 11008, 32, 32, 8, 32000, 2048];
        let bytes: Vec<u8> = values.into_iter().flat_map(i32::to_le_bytes).collect();
        let mut cursor = Cursor::new(bytes);

        let config = Config::from_reader(&mut cursor).unwrap();

        assert_eq!(
            config,
            Config {
                dim: 4096,
                hidden_dim: 11008,
                n_layers: 32,
                n_heads: 32,
                n_kv_heads: 8,
                vocab_size: 32000,
                seq_len: 2048,
            }
        );
        assert_eq!(config.head_size(), 128);
        assert_eq!(config.kv_dim(), 1024);
    }

    #[test]
    fn rejects_invalid_head_relationships() {
        let values = [1024_i32, 4096, 16, 10, 3, 32000, 1024];
        let bytes: Vec<u8> = values.into_iter().flat_map(i32::to_le_bytes).collect();
        let mut cursor = Cursor::new(bytes);

        let error = Config::from_reader(&mut cursor).unwrap_err();

        assert_eq!(error.kind(), std::io::ErrorKind::InvalidData);
    }

    #[test]
    fn rejects_negative_fields() {
        let values = [1024_i32, -1, 16, 8, 8, 32000, 1024];
        let bytes: Vec<u8> = values.into_iter().flat_map(i32::to_le_bytes).collect();
        let mut cursor = Cursor::new(bytes);

        let error = Config::from_reader(&mut cursor).unwrap_err();

        assert_eq!(error.kind(), std::io::ErrorKind::InvalidData);
    }
}

