use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub dim: usize,
    pub hidden_dim: usize,
    pub n_layers: usize,
    pub n_heads: usize,
    pub n_kv_heads: usize,
    pub vocab_size: usize,
    pub seq_len: usize,
}

impl Config {
    pub const HEADER_SIZE: usize = 7 * std::mem::size_of::<i32>();

    pub fn from_file(path: impl AsRef<Path>) -> io::Result<Self> {
        let mut file = File::open(path)?;
        Self::from_reader(&mut file)
    }

    pub fn from_reader(reader: &mut impl Read) -> io::Result<Self> {
        let config = Self {
            dim: read_usize(reader, "dim")?,
            hidden_dim: read_usize(reader, "hidden_dim")?,
            n_layers: read_usize(reader, "n_layers")?,
            n_heads: read_usize(reader, "n_heads")?,
            n_kv_heads: read_usize(reader, "n_kv_heads")?,
            vocab_size: read_usize(reader, "vocab_size")?,
            seq_len: read_usize(reader, "seq_len")?,
        };

        config.validate()?;
        Ok(config)
    }

    pub fn validate(&self) -> io::Result<()> {
        if self.dim == 0 {
            return Err(invalid_data("dim must be greater than 0"));
        }
        if self.hidden_dim == 0 {
            return Err(invalid_data("hidden_dim must be greater than 0"));
        }
        if self.n_layers == 0 {
            return Err(invalid_data("n_layers must be greater than 0"));
        }
        if self.n_heads == 0 {
            return Err(invalid_data("n_heads must be greater than 0"));
        }
        if self.n_kv_heads == 0 {
            return Err(invalid_data("n_kv_heads must be greater than 0"));
        }
        if self.vocab_size == 0 {
            return Err(invalid_data("vocab_size must be greater than 0"));
        }
        if self.seq_len == 0 {
            return Err(invalid_data("seq_len must be greater than 0"));
        }
        if self.dim % self.n_heads != 0 {
            return Err(invalid_data("dim must be divisible by n_heads"));
        }
        if self.n_heads % self.n_kv_heads != 0 {
            return Err(invalid_data("n_heads must be divisible by n_kv_heads"));
        }
        Ok(())
    }

    pub fn head_size(&self) -> usize {
        self.dim / self.n_heads
    }

    pub fn kv_dim(&self) -> usize {
        self.dim * self.n_kv_heads / self.n_heads
    }
}

fn read_usize(reader: &mut impl Read, field: &str) -> io::Result<usize> {
    let mut bytes = [0_u8; 4];
    reader.read_exact(&mut bytes)?;
    let value = i32::from_le_bytes(bytes);
    usize::try_from(value).map_err(|_| invalid_data(&format!("{field} must be non-negative")))
}

fn invalid_data(message: &str) -> io::Error {
    io::Error::new(io::ErrorKind::InvalidData, message)
}

#[cfg(test)]
mod tests {
    use super::Config;
    use std::io::{Cursor, ErrorKind};

    fn encode_header(values: [i32; 7]) -> Vec<u8> {
        values.into_iter().flat_map(i32::to_le_bytes).collect()
    }

    #[test]
    fn reads_header() {
        let mut cursor = Cursor::new(encode_header([4096, 11008, 32, 32, 8, 32000, 2048]));

        let config = Config::from_reader(&mut cursor).unwrap();

        assert_eq!(
            config,
            Config {
                dim: 4096,
                hidden_dim: 11008,
                n_layers: 32,
                n_heads: 32,
                n_kv_heads: 8,
                vocab_size: 32000,
                seq_len: 2048,
            }
        );
        assert_eq!(config.head_size(), 128);
        assert_eq!(config.kv_dim(), 1024);
    }

    #[test]
    fn rejects_negative_field() {
        let mut cursor = Cursor::new(encode_header([4096, -1, 32, 32, 8, 32000, 2048]));

        let error = Config::from_reader(&mut cursor).unwrap_err();

        assert_eq!(error.kind(), ErrorKind::InvalidData);
    }

    #[test]
    fn rejects_invalid_head_shape() {
        let mut cursor = Cursor::new(encode_header([4096, 11008, 32, 30, 8, 32000, 2048]));

        let error = Config::from_reader(&mut cursor).unwrap_err();

        assert_eq!(error.kind(), ErrorKind::InvalidData);
    }
}

