use crate::config::Config;
use std::fs::File;
use std::io::{self, Read};
use std::ops::Range;
use std::path::Path;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WeightLayout {
    pub token_embedding_table: Range<usize>,
    pub rms_att_weight: Range<usize>,
    pub wq: Range<usize>,
    pub wk: Range<usize>,
    pub wv: Range<usize>,
    pub wo: Range<usize>,
    pub rms_ffn_weight: Range<usize>,
    pub w1: Range<usize>,
    pub w2: Range<usize>,
    pub w3: Range<usize>,
    pub rms_final_weight: Range<usize>,
    pub freq_cis_real: Range<usize>,
    pub freq_cis_imag: Range<usize>,
    pub wcls: Option<Range<usize>>,
}

#[derive(Debug, Clone)]
pub struct TransformerWeights {
    data: Vec<f32>,
    layout: WeightLayout,
}

impl TransformerWeights {
    pub fn from_file(path: impl AsRef<Path>, config: &Config) -> io::Result<Self> {
        let mut file = File::open(path)?;
        Self::from_reader(&mut file, config)
    }

    pub fn from_reader(reader: &mut impl Read, config: &Config) -> io::Result<Self> {
        let required_layout = WeightLayout::for_config(config, false);
        let mut data = vec![0.0_f32; required_layout.total_floats()];

        for value in &mut data {
            *value = read_f32(reader)?;
        }

        let trailing = read_trailing_f32s(reader)?;
        if trailing.is_empty() {
            return Ok(Self {
                data,
                layout: required_layout,
            });
        }

        let wcls_len = config.vocab_size * config.dim;
        if trailing.len() != wcls_len {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "optional wcls size does not match vocab_size * dim",
            ));
        }

        let start = data.len();
        data.extend_from_slice(&trailing);
        let end = data.len();

        Ok(Self {
            data,
            layout: WeightLayout {
                wcls: Some(start..end),
                ..required_layout
            },
        })
    }

    pub fn layout(&self) -> &WeightLayout {
        &self.layout
    }

    pub fn total_floats(&self) -> usize {
        self.data.len()
    }

    pub fn token_embedding_table(&self) -> &[f32] {
        self.slice(&self.layout.token_embedding_table)
    }

    pub fn rms_att_weight(&self) -> &[f32] {
        self.slice(&self.layout.rms_att_weight)
    }

    pub fn wq(&self) -> &[f32] {
        self.slice(&self.layout.wq)
    }

    pub fn wk(&self) -> &[f32] {
        self.slice(&self.layout.wk)
    }

    pub fn wv(&self) -> &[f32] {
        self.slice(&self.layout.wv)
    }

    pub fn wo(&self) -> &[f32] {
        self.slice(&self.layout.wo)
    }

    pub fn rms_ffn_weight(&self) -> &[f32] {
        self.slice(&self.layout.rms_ffn_weight)
    }

    pub fn w1(&self) -> &[f32] {
        self.slice(&self.layout.w1)
    }

    pub fn w2(&self) -> &[f32] {
        self.slice(&self.layout.w2)
    }

    pub fn w3(&self) -> &[f32] {
        self.slice(&self.layout.w3)
    }

    pub fn rms_final_weight(&self) -> &[f32] {
        self.slice(&self.layout.rms_final_weight)
    }

    pub fn freq_cis_real(&self) -> &[f32] {
        self.slice(&self.layout.freq_cis_real)
    }

    pub fn freq_cis_imag(&self) -> &[f32] {
        self.slice(&self.layout.freq_cis_imag)
    }

    pub fn wcls(&self) -> Option<&[f32]> {
        self.layout.wcls.as_ref().map(|range| self.slice(range))
    }

    fn slice(&self, range: &Range<usize>) -> &[f32] {
        &self.data[range.clone()]
    }
}

impl WeightLayout {
    pub fn for_config(config: &Config, include_wcls: bool) -> Self {
        let mut cursor = 0;

        let token_embedding_table = take_range(&mut cursor, config.vocab_size * config.dim);
        let rms_att_weight = take_range(&mut cursor, config.n_layers * config.dim);
        let wq = take_range(&mut cursor, config.n_layers * config.dim * config.dim);
        let wk = take_range(&mut cursor, config.n_layers * config.dim * config.kv_dim());
        let wv = take_range(&mut cursor, config.n_layers * config.dim * config.kv_dim());
        let wo = take_range(&mut cursor, config.n_layers * config.dim * config.dim);
        let rms_ffn_weight = take_range(&mut cursor, config.n_layers * config.dim);
        let w1 = take_range(&mut cursor, config.n_layers * config.hidden_dim * config.dim);
        let w2 = take_range(&mut cursor, config.n_layers * config.dim * config.hidden_dim);
        let w3 = take_range(&mut cursor, config.n_layers * config.hidden_dim * config.dim);
        let rms_final_weight = take_range(&mut cursor, config.dim);
        let rope_size = config.seq_len * config.head_size() / 2;
        let freq_cis_real = take_range(&mut cursor, rope_size);
        let freq_cis_imag = take_range(&mut cursor, rope_size);
        let wcls = include_wcls.then(|| take_range(&mut cursor, config.vocab_size * config.dim));

        Self {
            token_embedding_table,
            rms_att_weight,
            wq,
            wk,
            wv,
            wo,
            rms_ffn_weight,
            w1,
            w2,
            w3,
            rms_final_weight,
            freq_cis_real,
            freq_cis_imag,
            wcls,
        }
    }

    pub fn total_floats(&self) -> usize {
        self.wcls
            .as_ref()
            .map_or(self.freq_cis_imag.end, |range| range.end)
    }
}

fn take_range(cursor: &mut usize, len: usize) -> Range<usize> {
    let start = *cursor;
    *cursor += len;
    start..*cursor
}

fn read_f32(reader: &mut impl Read) -> io::Result<f32> {
    let mut bytes = [0_u8; 4];
    reader.read_exact(&mut bytes)?;
    Ok(f32::from_le_bytes(bytes))
}

fn read_trailing_f32s(reader: &mut impl Read) -> io::Result<Vec<f32>> {
    let mut trailing = Vec::new();
    reader.read_to_end(&mut trailing)?;
    if trailing.is_empty() {
        return Ok(Vec::new());
    }
    if trailing.len() % std::mem::size_of::<f32>() != 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "trailing weight bytes are not a multiple of 4",
        ));
    }

    Ok(trailing
        .chunks_exact(4)
        .map(|chunk| f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]))
        .collect())
}

#[cfg(test)]
mod tests {
    use super::{TransformerWeights, WeightLayout};
    use crate::config::Config;
    use std::io::Cursor;

    fn test_config() -> Config {
        Config {
            dim: 4,
            hidden_dim: 6,
            n_layers: 2,
            n_heads: 2,
            n_kv_heads: 1,
            vocab_size: 8,
            seq_len: 4,
        }
    }

    fn encode_f32s(values: impl IntoIterator<Item = f32>) -> Vec<u8> {
        values.into_iter().flat_map(f32::to_le_bytes).collect()
    }

    #[test]
    fn computes_expected_layout() {
        let config = test_config();
        let layout = WeightLayout::for_config(&config, true);

        assert_eq!(layout.token_embedding_table, 0..32);
        assert_eq!(layout.rms_att_weight, 32..40);
        assert_eq!(layout.wq, 40..72);
        assert_eq!(layout.wk, 72..88);
        assert_eq!(layout.wv, 88..104);
        assert_eq!(layout.wo, 104..136);
        assert_eq!(layout.rms_ffn_weight, 136..144);
        assert_eq!(layout.w1, 144..192);
        assert_eq!(layout.w2, 192..240);
        assert_eq!(layout.w3, 240..288);
        assert_eq!(layout.rms_final_weight, 288..292);
        assert_eq!(layout.freq_cis_real, 292..296);
        assert_eq!(layout.freq_cis_imag, 296..300);
        assert_eq!(layout.wcls, Some(300..332));
        assert_eq!(layout.total_floats(), 332);
    }

    #[test]
    fn loads_weights_without_classifier() {
        let config = test_config();
        let layout = WeightLayout::for_config(&config, false);
        let bytes = encode_f32s((0..layout.total_floats()).map(|v| v as f32));
        let mut cursor = Cursor::new(bytes);

        let weights = TransformerWeights::from_reader(&mut cursor, &config).unwrap();

        assert_eq!(weights.total_floats(), 300);
        assert_eq!(weights.token_embedding_table().len(), 32);
        assert_eq!(weights.rms_att_weight().len(), 8);
        assert_eq!(weights.wq().len(), 32);
        assert_eq!(weights.wk().len(), 16);
        assert_eq!(weights.wv().len(), 16);
        assert_eq!(weights.wo().len(), 32);
        assert_eq!(weights.rms_ffn_weight().len(), 8);
        assert_eq!(weights.w1().len(), 48);
        assert_eq!(weights.w2().len(), 48);
        assert_eq!(weights.w3().len(), 48);
        assert_eq!(weights.rms_final_weight().len(), 4);
        assert_eq!(weights.freq_cis_real().len(), 4);
        assert_eq!(weights.freq_cis_imag().len(), 4);
        assert_eq!(weights.wcls(), None);
    }

    #[test]
    fn loads_optional_classifier() {
        let config = test_config();
        let layout = WeightLayout::for_config(&config, true);
        let bytes = encode_f32s((0..layout.total_floats()).map(|v| v as f32));
        let mut cursor = Cursor::new(bytes);

        let weights = TransformerWeights::from_reader(&mut cursor, &config).unwrap();

        assert_eq!(weights.total_floats(), 332);
        assert_eq!(weights.wcls().unwrap().len(), 32);
        assert_eq!(weights.wcls().unwrap()[0], 300.0);
    }
}

