use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

#[derive(Debug, Clone)]
pub struct Tokenizer {
    vocab: Vec<Vec<u8>>,
    scores: Vec<f32>,
    token_to_id: HashMap<Vec<u8>, usize>,
    max_token_length: usize,
    bos_id: Option<usize>,
    eos_id: Option<usize>,
    unk_id: Option<usize>,
}

impl Tokenizer {
    pub fn from_file(path: impl AsRef<Path>, vocab_size: usize) -> io::Result<Self> {
        let mut file = File::open(path)?;
        Self::from_reader(&mut file, vocab_size)
    }

    pub fn from_reader(reader: &mut impl Read, vocab_size: usize) -> io::Result<Self> {
        let max_token_length = read_u32(reader)? as usize;
        let mut vocab = Vec::with_capacity(vocab_size);
        let mut scores = Vec::with_capacity(vocab_size);
        let mut token_to_id = HashMap::with_capacity(vocab_size);

        for id in 0..vocab_size {
            let score = read_f32(reader)?;
            let token_len = read_i32(reader)?;
            let token_len = usize::try_from(token_len).map_err(|_| {
                io::Error::new(io::ErrorKind::InvalidData, "token length must be non-negative")
            })?;

            let mut token = vec![0_u8; token_len];
            reader.read_exact(&mut token)?;

            token_to_id.insert(token.clone(), id);
            vocab.push(token);
            scores.push(score);
        }

        let bos_id = token_to_id.get(b"<s>".as_slice()).copied().or(Some(1).filter(|&id| id < vocab_size));
        let eos_id = token_to_id.get(b"</s>".as_slice()).copied().or(Some(2).filter(|&id| id < vocab_size));
        let unk_id = token_to_id.get(b"<unk>".as_slice()).copied();

        Ok(Self {
            vocab,
            scores,
            token_to_id,
            max_token_length,
            bos_id,
            eos_id,
            unk_id,
        })
    }

    pub fn vocab_size(&self) -> usize {
        self.vocab.len()
    }

    pub fn max_token_length(&self) -> usize {
        self.max_token_length
    }

    pub fn bos_id(&self) -> Option<usize> {
        self.bos_id
    }

    pub fn eos_id(&self) -> Option<usize> {
        self.eos_id
    }

    pub fn unk_id(&self) -> Option<usize> {
        self.unk_id
    }

    pub fn decode(&self, token_id: usize) -> Option<&[u8]> {
        self.vocab.get(token_id).map(Vec::as_slice)
    }

    pub fn decode_to_string(&self, token_id: usize) -> Option<String> {
        self.decode(token_id)
            .map(|bytes| String::from_utf8_lossy(bytes).into_owned())
    }

    pub fn token_id(&self, piece: &[u8]) -> Option<usize> {
        self.token_to_id.get(piece).copied()
    }

    pub fn encode(&self, text: &str, add_bos: bool, add_eos: bool) -> Vec<usize> {
        let mut tokens = Vec::new();

        if add_bos {
            if let Some(id) = self.bos_id {
                tokens.push(id);
            }
        }

        let mut pieces = self.initial_pieces(text.as_bytes());
        self.merge_best_pairs(&mut pieces);
        tokens.extend(pieces);

        if add_eos {
            if let Some(id) = self.eos_id {
                tokens.push(id);
            }
        }

        tokens
    }

    fn initial_pieces(&self, text: &[u8]) -> Vec<usize> {
        let mut pieces = Vec::new();
        let mut index = 0;

        while index < text.len() {
            let remaining = &text[index..];
            let mut matched = None;
            let max_len = self.max_token_length.min(remaining.len());

            for len in (1..=max_len).rev() {
                if let Some(id) = self.token_to_id.get(&remaining[..len]) {
                    matched = Some((*id, len));
                    break;
                }
            }

            if let Some((id, len)) = matched {
                pieces.push(id);
                index += len;
                continue;
            }

            let char_len = utf8_char_width(remaining[0]).min(remaining.len());
            let char_bytes = &remaining[..char_len];

            if let Some(id) = self.token_to_id.get(char_bytes) {
                pieces.push(*id);
            } else {
                self.push_byte_fallback(char_bytes, &mut pieces);
            }

            index += char_len;
        }

        pieces
    }

    fn merge_best_pairs(&self, pieces: &mut Vec<usize>) {
        loop {
            if pieces.len() < 2 {
                return;
            }

            let mut best: Option<(usize, usize, f32)> = None;

            for i in 0..pieces.len() - 1 {
                let merged = self.concat_tokens(pieces[i], pieces[i + 1]);
                if let Some(id) = self.token_to_id.get(merged.as_slice()) {
                    let score = self.scores[*id];
                    if best.as_ref().is_none_or(|(_, _, best_score)| score > *best_score) {
                        best = Some((i, *id, score));
                    }
                }
            }

            let Some((index, merged_id, _)) = best else {
                return;
            };

            pieces[index] = merged_id;
            pieces.remove(index + 1);
        }
    }

    fn concat_tokens(&self, left: usize, right: usize) -> Vec<u8> {
        let mut merged = Vec::with_capacity(self.vocab[left].len() + self.vocab[right].len());
        merged.extend_from_slice(&self.vocab[left]);
        merged.extend_from_slice(&self.vocab[right]);
        merged
    }

    fn push_byte_fallback(&self, bytes: &[u8], out: &mut Vec<usize>) {
        for &byte in bytes {
            let candidates = [[byte], format!("<0x{byte:02X}>").into_bytes()];

            let mut pushed = false;
            for candidate in candidates {
                if let Some(id) = self.token_to_id.get(candidate.as_slice()) {
                    out.push(*id);
                    pushed = true;
                    break;
                }
            }

            if !pushed {
                if let Some(unk_id) = self.unk_id {
                    out.push(unk_id);
                }
            }
        }
    }
}

fn read_u32(reader: &mut impl Read) -> io::Result<u32> {
    let mut bytes = [0_u8; 4];
    reader.read_exact(&mut bytes)?;
    Ok(u32::from_le_bytes(bytes))
}

fn read_i32(reader: &mut impl Read) -> io::Result<i32> {
    let mut bytes = [0_u8; 4];
    reader.read_exact(&mut bytes)?;
    Ok(i32::from_le_bytes(bytes))
}

fn read_f32(reader: &mut impl Read) -> io::Result<f32> {
    let mut bytes = [0_u8; 4];
    reader.read_exact(&mut bytes)?;
    Ok(f32::from_le_bytes(bytes))
}

fn utf8_char_width(first_byte: u8) -> usize {
    match first_byte {
        0x00..=0x7f => 1,
        0xc0..=0xdf => 2,
        0xe0..=0xef => 3,
        0xf0..=0xf7 => 4,
        _ => 1,
    }
}

