+    fn initial_pieces(&self, text: &[u8]) -> Vec<usize> {
+        let mut pieces = Vec::new();
+        let mut index = 0;
+
+        while index < text.len() {
+            let remaining = &text[index..];
+            let mut matched = None;
+            let max_len = self.max_token_length.min(remaining.len());
+
+            for len in (1..=max_len).rev() {
+                if let Some(id) = self.token_to_id.get(&remaining[..len]) {
+                    matched = Some((*id, len));
+                    break;
+                }
+            }
+
+            if let Some((id, len)) = matched {
+                pieces.push(id);
+                index += len;
+                continue;
+            }
+
+            let char_len = utf8_char_width(remaining[0]).min(remaining.len());
+            let char_bytes = &remaining[..char_len];
+
+            if let Some(id) = self.token_to_id.get(char_bytes) {
+                pieces.push(*id);
+            } else {
+                self.push_byte_fallback(char_bytes, &mut pieces);
+            }
+
+            index += char_len;
+        }
+
+        pieces
+    }
+
+    fn merge_best_pairs(&self, pieces: &mut Vec<usize>) {
+        loop {
+            if pieces.len() < 2 {
+                return;
+            }
+
+            let mut best: Option<(usize, usize, f32)> = None;
+
+            for i in 0..pieces.len() - 1 {
+                let merged = self.concat_tokens(pieces[i], pieces[i + 1]);
+                if let Some(id) = self.token_to_id.get(merged.as_slice()) {
+                    let score = self.scores[*id];
+                    if best.as_ref().is_none_or(|(_, _, best_score)| score > *best_score) {
+                        best = Some((i, *id, score));
+                    }
+                }
+            }
+
+            let Some((index, merged_id, _)) = best else {
+                return;
+            };
+
+            pieces[index] = merged_id;
+            pieces.remove(index + 1);
+        }
+    }
