+    fn concat_tokens(&self, left: usize, right: usize) -> Vec<u8> {
+        let mut merged = Vec::with_capacity(self.vocab[left].len() + self.vocab[right].len());
+        merged.extend_from_slice(&self.vocab[left]);
+        merged.extend_from_slice(&self.vocab[right]);
+        merged
+    }
+
+    fn push_byte_fallback(&self, bytes: &[u8], out: &mut Vec<usize>) {
+        for &byte in bytes {
+            let candidates = [[byte], format!("<0x{byte:02X}>").into_bytes()];
+
+            let mut pushed = false;
+            for candidate in candidates {
+                if let Some(id) = self.token_to_id.get(candidate.as_slice()) {
+                    out.push(*id);
+                    pushed = true;
+                    break;
+                }
+            }
+
+            if !pushed {
+                if let Some(unk_id) = self.unk_id {
+                    out.push(unk_id);
+                }
+            }
+        }
+    }
+}
+
+fn read_u32(reader: &mut impl Read) -> io::Result<u32> {
+    let mut bytes = [0_u8; 4];
+    reader.read_exact(&mut bytes)?;
+    Ok(u32::from_le_bytes(bytes))
+}
+
+fn read_i32(reader: &mut impl Read) -> io::Result<i32> {
+    let mut bytes = [0_u8; 4];
+    reader.read_exact(&mut bytes)?;
+    Ok(i32::from_le_bytes(bytes))
+}
+
+fn read_f32(reader: &mut impl Read) -> io::Result<f32> {
+    let mut bytes = [0_u8; 4];
+    reader.read_exact(&mut bytes)?;
+    Ok(f32::from_le_bytes(bytes))
+}
+
+fn utf8_char_width(first_byte: u8) -> usize {
+    match first_byte {
+        0x00..=0x7f => 1,
+        0xc0..=0xdf => 2,
+        0xe0..=0xef => 3,
+        0xf0..=0xf7 => 4,
+        _ => 1,
+    }
+}

