        bytes.extend_from_slice(&[1, 2, 3, 4, 5]);
        let mut reader = bytes.as_slice();

        let err = Weights::from_reader(&config, &mut reader).expect_err("weights should fail");
        assert!(matches!(err, WeightsError::TrailingBytes { .. }));
    }

