        let shared_weights = values[5] > 0;
        let vocab_size = values[5].unsigned_abs() as usize;

        let config = Self::new(
            positive_i32_to_usize(values[0], "dim")?,
            positive_i32_to_usize(values[1], "hidden_dim")?,
