+            let sin = angle.sin();
+            let x0 = head[pair_index];
+            let x1 = head[pair_index + 1];
+            head[pair_index] = x0 * cos - x1 * sin;
+            head[pair_index + 1] = x0 * sin + x1 * cos;
+        }
+    }
