        let sin = angle.sin();

        rotate_pair(q, i, cos, sin);
        if i < kv_dim {
            rotate_pair(k, i, cos, sin);
        }
    }
}

fn rotate_pair(values: &mut [f32], index: usize, cos: f32, sin: f32) {
    let v0 = values[index];
    let v1 = values[index + 1];
    values[index] = v0 * cos - v1 * sin;
    values[index + 1] = v0 * sin + v1 * cos;
}

